// Attempt to enumerate all open tabs in the browser
const tabInfo = [];

// Try various browser APIs to list tabs
try {
  // Chrome/Edge extension context might have page tab API
  if (typeof page !== 'undefined' && typeof page.tabs !== 'undefined') {
    for (const tab of page.tabs) {
      tabInfo.push({ id: tab.id, url: tab.url, title: tab.title });
    }
  } else {
    // Fallback: try window-level tab enumeration
    console.log('page.tabs not available');

    // Try navigator or other APIs
    if (typeof navigator !== 'undefined') {
      console.log('navigator:', Object.keys(navigator).slice(0, 20));
    }

    // Check if we're in an extension context
    const isExtension = window.location.protocol === 'chrome-extension://' || 
                         window.location.hostname.includes('webbrain');
    console.log('Is extension context:', isExtension);

    // Try to access page/tab APIs directly
    try {
      const win = window;
      // Look for any tab-related APIs
      for (const key of Object.keys(win)) {
        if (key.toLowerCase().includes('tab') || key.toLowerCase().includes('tabbar')) {
          console.log('Found tab API:', key, win[key]);
        }
      }
    } catch(e) {
      console.log('JS error scanning window:', e.message);
    }
  }
} catch (e) {
  console.log('Error:', e.message);
}

// Also try the browser's built-in tab management via chrome.tabs API if accessible
try {
  const result = JSON.parse(await new Promise(r => setTimeout(() => {
    const chrome = window.chrome || window.browser || window.app;
    if (chrome && typeof chrome.tabs !== 'undefined') {
      chrome.tabs.enumerate({ includeRestoredTabs: true, includeSelectedTabs: false })
        .then(tabs => {
          r(tabs);
        });
    } else {
      r(null);
    }
  }, 1000)));
  if (result) {
    tabInfo.push({ source: 'chrome.tabs.enumerate', count: result.length, tabs: result.map(t => ({id: t.id, url: t.url, title: t.title, state: t.state}))});
  }
} catch(e) {
  console.log('Chrome tabs enumerate error:', e.message);
}

// Output what we found
console.log('=== TAB INFO ===');
console.log(JSON.stringify(tabInfo, null, 2));
